/*
 * See https://web.archive.org/web/20210331174704/https://bestofsudoku.com/sudoku-strategy
 */
import { bitCount, getterFunctionNames } from './shared';
const genericNakedPairsSolver = (sudoku, getterFunctionName) => {
    let anyChanged = false;
    for (let structureIndex = 0; structureIndex < 9; ++structureIndex) {
        const structure = sudoku[getterFunctionName](structureIndex);
        const summary = new Map();
        for (const [index, cell] of structure.entries()) {
            if (cell.content !== undefined) {
                continue;
            }
            for (const number of cell.possible) {
                summary.set(index, (summary.get(index) ?? 0) | (2 ** (+number - 1)));
            }
        }
        const equalKeys = new Map();
        for (const [index, key] of summary) {
            let array = equalKeys.get(key);
            if (!array) {
                array = [];
                equalKeys.set(key, array);
            }
            array.push(index);
        }
        for (const [key, numbers] of equalKeys) {
            if (bitCount(key) !== numbers.length || numbers.length > 8) {
                continue;
            }
            for (let number = 0; number <= Math.log2(key); ++number) {
                if (((2 ** number) & key) === 0) {
                    continue;
                }
                const stringNumber = `${number + 1}`;
                for (const [index, cell] of structure.entries()) {
                    if (!numbers.includes(index) && cell.possible.has(stringNumber)) {
                        anyChanged = true;
                        cell.possible.delete(stringNumber);
                    }
                }
            }
        }
    }
    console.log(getterFunctionName, anyChanged);
    return anyChanged;
};
export const nakedPairs = (sudoku) => {
    let anyChanged = false;
    console.group('naked-pairs');
    for (const key of getterFunctionNames) {
        anyChanged = genericNakedPairsSolver(sudoku, key) || anyChanged;
    }
    console.log(anyChanged);
    console.groupEnd();
    return anyChanged;
};
