import { uniqueId } from 'lodash';
const emptyCellPossibles = () => new Set(Array.from({ length: 9 }, (_v, index) => `${index + 1}`));
export class Cell {
    constructor() {
        this.possible = emptyCellPossibles();
        this.key = uniqueId('cell-');
        this.valid = true;
        this.setValidity = () => {
            this.valid
                = typeof this.content === 'undefined'
                    ? this.possible.size !== 0
                    : (/^[1-9]$/).test(this.content);
            return this;
        };
        this.setContent = (content) => {
            this.content = content.trim();
            this.possible.clear();
            return this.setValidity();
        };
        this.clear = () => {
            this.content = undefined;
            this.possible = emptyCellPossibles();
            this.valid = true;
            return this;
        };
    }
}
